const analytics = $('Fetch Agent Studio Analytics').item.json;
const agents = $('Fetch All Agents').item.json;

const now = new Date();
const weekStart = new Date(now - 7 * 24 * 60 * 60 * 1000);

const agentList = (agents.data || agents || [])
  .slice(0, 10)
  .map(a => `- ${a.name} (${a.model || 'default model'})`)
  .join('\n');

const analyticsStr = JSON.stringify(analytics, null, 2).slice(0, 2000);

const message = `Generate a professional weekly performance report for Agent Studio.

Report Period: ${weekStart.toDateString()} - ${now.toDateString()}

Raw Analytics Data:
${analyticsStr}

Active Agents (${(agents.data || agents || []).length} total):
${agentList}

Please provide:
1. Executive Summary (2-3 sentences)
2. Key Metrics highlights
3. Top performing agents
4. Areas for improvement
5. Recommendations for next week

Format as a clean, professional report suitable for stakeholder distribution.`;

return [{ json: { prompt: message, week_start: weekStart.toISOString(), week_end: now.toISOString() } }];

const agentResponse = $json.data?.messages?.find(m => m.role === 'assistant')?.content || 'Report generation failed.';
const promptData = $('Build Report Prompt').item.json;

const weekLabel = new Date(promptData.week_start).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
  + ' - '
  + new Date(promptData.week_end).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

return [{
  json: {
    subject: `Agent Studio Weekly Report: ${weekLabel}`,
    html_body: `<html><body style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto; padding: 20px;">
<h1 style="color: #1a1a2e;">📊 Agent Studio Weekly Report</h1>
<p style="color: #666;">${weekLabel}</p>
<hr>
<div style="white-space: pre-wrap; line-height: 1.6;">${agentResponse.replace(/\n/g, '<br>')}</div>
<hr>
<p style="color: #999; font-size: 12px;">Generated automatically by Agent Studio × n8n</p>
</body></html>`,
    text_body: agentResponse
  }
}];
